93	  { label: "Docs", description: "API docs and guides", href: "https://docs.warp.dev/", icon: <FileTextIcon className="size-4" /> },
94	  { label: "Blog", description: "News and product updates", href: "/blog", icon: <PencilIcon className="size-4" /> },
