111	  { label: "Overview", description: "Secure, compliant agentic development for your org", href: "/enterprise", icon: <ShieldCheckIcon className="size-4" /> },
112	  { label: "Customers", description: "Teams shipping faster with Warp", href: "/customers", icon: <UsersIcon className="size-4" /> },
113	];
114	
115	function FlyoutItemRow({ item, hoverOnWrapper }: { item: FlyoutItem; hoverOnWrapper?: boolean }) {
116	  const external = !!item.external;
117	  const anchor = (
118	    <a
119	      href={item.href}
120	      target={external ? "_blank" : undefined}
121	      rel={external ? "noopener noreferrer" : undefined}
122	      className={
123	        hoverOnWrapper
124	          ? "flex items-start gap-3 rounded-lg p-3 focus:outline-none focus-visible:ring-2 focus-visible:ring-(--color-text)"
125	          : "group flex items-start gap-3 rounded-lg p-3 hover:bg-(--color-text)/5 focus:outline-none focus-visible:ring-2 focus-visible:ring-(--color-text)"
126	      }
127	    >
128	      <span className="mt-0.5 inline-flex size-6 shrink-0 items-center justify-center rounded-md bg-(--color-text)/5 text-(--color-text-secondary) ring-1 ring-inset ring-(--color-border)">
