135	        </span>
136	        <span className="block text-sm text-(--color-muted)">{item.description}</span>
137	      </span>
138	    </a>
139	  );
140	  if (hoverOnWrapper) {
141	    return <div className="group rounded-lg hover:bg-(--color-text)/5">{anchor}</div>;
142	  }
143	  return anchor;
144	}
145	
146	function FlyoutItemProduct({ item }: { item: FlyoutItem }) {
147	  return (
148	    <a
149	      href={item.href}
150	      className="group flex items-start gap-3 rounded-lg p-3 hover:bg-(--color-text)/5"
151	    >
152	      <span className="mt-0.5 inline-flex size-6 shrink-0 items-center justify-center">
153	        {item.icon}
154	      </span>
155	      <div>
156	        <p className="inline-flex items-center gap-1 text-sm font-semibold text-(--color-text)">{item.label}</p>
157	        <p className="mt-0.5 text-sm text-(--color-muted)">{item.description}</p>
158	      </div>
159	    </a>
160	  );
161	}
162	
163	const flyoutPanelBase = "absolute top-full left-0 z-[9999] mt-0 rounded-(--img-radius) bg-[#0C0C0C] p-2 shadow-lg ring-1 ring-(--color-border)";
164	const flyoutSmallWidth = "w-max max-w-[calc(100vw-3rem)] lg:max-w-2xl";
165	const flyoutWideWidth = "w-[calc(100vw-3rem)] max-w-3xl";
166	
167	type ActiveFlyout = "products" | "solutions" | "resources" | "enterprise" | null;
168	
169	export default function Navbar() {
170	  const [activeFlyout, setActiveFlyout] = useState<ActiveFlyout>(null);
171	  const [mobileOpen, setMobileOpen] = useState(false);
172	  const navRef = useRef<HTMLDivElement>(null);
173	  const leaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
174	
175	  useEffect(() => {
176	    function handleClickOutside(e: MouseEvent) {
177	      if (!navRef.current?.contains(e.target as Node)) {
178	        setActiveFlyout(null);
179	      }
180	    }
181	    document.addEventListener("mousedown", handleClickOutside);
182	    return () => document.removeEventListener("mousedown", handleClickOutside);
183	  }, []);
184	
185	  useEffect(() => {
186	    document.body.classList.toggle("overflow-hidden", mobileOpen);
187	    return () => { document.body.classList.remove("overflow-hidden"); };
188	  }, [mobileOpen]);
189	
190	  const cancelLeave = useCallback(() => {
191	    if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
192	  }, []);
193	
194	  const scheduleLeave = useCallback(() => {
195	    leaveTimerRef.current = setTimeout(() => setActiveFlyout(null), 200);
196	  }, []);
197	
198	  const openFlyout = useCallback((name: ActiveFlyout) => {
199	    cancelLeave();
200	    setActiveFlyout(name);
201	  }, [cancelLeave]);
202	
203	  const toggleFlyout = (name: ActiveFlyout) => {
204	    setActiveFlyout(prev => prev === name ? null : name);
205	  };
206	
207	  return (
