220	            <div className="flex items-stretch gap-1 max-lg:hidden">
221	
222	              {/* Products */}
223	              <div
224	                className="relative flex items-center"
225	                onMouseEnter={() => openFlyout("products")}
226	                onMouseLeave={scheduleLeave}
227	              >
228	                <button
229	                  onClick={() => toggleFlyout("products")}
230	                  className="inline-flex cursor-default items-center gap-1 rounded-lg px-2.5 py-1 text-sm/7 font-medium text-(--color-text) hover:bg-text/5"
231	                >
